/* adm-system-sequence-strategy-sql-oracle.xml - updateSequenceStrategy */
INSERT INTO TADMIN_MST_SEQ_STG (
	STGNM, SEQNM, STARTNO, PREFIX, SUFFIX, LENGTH, DATEFORMAT,
	SEQINITUSEYN, SEQRESETCYCLE, DELYN,
	INSERTDATE, INSERTURKEY, UPDATEDATE, UPDATEURKEY
) VALUES (
	#{stgnm}, #{seqnm}, #{startno}, #{prefix}, #{suffix}, #{seqlength}, #{dateformat},
	#{seqinituseyn}, #{seqresetcycle}, #{delyn},
	#{sysdate}, #{surkey}, #{sysdate}, #{surkey}
)
ON CONFLICT (STGNM) DO UPDATE SET
	UPDATEURKEY = #{surkey},
	UPDATEDATE = #{sysdate}

		, DELYN = #{delyn}


		, STARTNO = #{startno}

	, PREFIX = #{prefix}
	, SUFFIX = #{suffix}

		, LENGTH = #{seqlength}


		, SEQNM = #{seqnm}

	, SEQINITUSEYN = #{seqinituseyn}
	, SEQRESETCYCLE = #{seqresetcycle}
	, DATEFORMAT = #{dateformat}

/* adm-system-sequence-strategy-sql-oracle.xml - deleteSequenceStrategy */
UPDATE TADMIN_MST_SEQ_STG
   SET DELYN = 'Y'
 WHERE STGNM = #{stgnm}
